"""Per-request bounded queue for streaming between pipeline stages."""
from __future__ import annotations

import asyncio
import logging
from dataclasses import dataclass
from typing import Any

logger = logging.getLogger(__name__)


@dataclass
class StreamItem:
    """A single item of streaming data between stages."""

    chunk_id: int
    data: Any
    from_stage: str
    metadata: dict[str, Any] | None = None


@dataclass
class StreamSignal:
    """Non-data queue event such as per-source EOS or error."""

    from_stage: str | None = None
    is_done: bool = False
    error: BaseException | None = None


class StreamQueue:
    """Manages per-request unbounded async queues for streaming between stages.

    Backpressure is applied at the sender stage / scheduler boundary before
    chunks enter this queue. The per-request queues here are unbounded so that
    ordered chunks are never dropped.

    Usage:
        sq.open("req-1")              # create queue for request
        sq.put("req-1", item)         # sender puts items
        item = await sq.get(...)      # consumer awaits next item (returns None on EOS)
        sq.close("req-1")             # cleanup
    """

    def __init__(self, max_pending: int = 16):
        self._max_pending = max_pending
        self._queues: dict[str, asyncio.Queue] = {}
        self._closed: set[str] = set()  # track closed request IDs for abort race

    def open(self, request_id: str) -> None:
        self._closed.discard(request_id)
        if request_id not in self._queues:
            self._queues[request_id] = (
                asyncio.Queue()
            )  # unbounded; backpressure at sender

    def has(self, request_id: str) -> bool:
        return request_id in self._queues

    def put(self, request_id: str, item: StreamItem) -> None:
        queue = self._queues.get(request_id)
        if queue is None:
            if request_id in self._closed:
                return  # silently drop — queue was closed (abort)
            raise KeyError(f"No queue for {request_id}")
        queue.put_nowait(item)

    def put_done(self, request_id: str, from_stage: str | None = None) -> None:
        queue = self._queues.get(request_id)
        if queue is None:
            return
        queue.put_nowait(StreamSignal(from_stage=from_stage, is_done=True))

    def put_error(
        self, request_id: str, error: BaseException, from_stage: str | None = None
    ) -> None:
        queue = self._queues.get(request_id)
        if queue is None:
            return
        queue.put_nowait(StreamSignal(from_stage=from_stage, error=error))

    async def get(self, request_id: str) -> StreamItem | None:
        """Get next item. Returns None when done or closed (abort)."""
        queue = self._queues.get(request_id)
        if queue is None:
            if request_id in self._closed:
                return None  # queue was closed — treat as done
            raise RuntimeError(f"No queue for {request_id}")

        try:
            item = queue.get_nowait()
        except asyncio.QueueEmpty:
            item = await queue.get()

        if isinstance(item, StreamSignal):
            if item.error:
                raise item.error
            return None
        return item

    async def get_with_source(self, request_id: str) -> StreamItem | StreamSignal:
        """Get next item or signal while preserving the upstream stage info."""
        queue = self._queues.get(request_id)
        if queue is None:
            if request_id in self._closed:
                return StreamSignal(is_done=True)  # abort signal
            raise RuntimeError(f"No queue for {request_id}")

        try:
            item = queue.get_nowait()
        except asyncio.QueueEmpty:
            item = await queue.get()
        return item

    def close(self, request_id: str) -> None:
        q = self._queues.pop(request_id, None)
        self._closed.add(request_id)
        # Cap _closed size to prevent unbounded growth
        if len(self._closed) > 10000:
            # Remove oldest entries (set is unordered, but bulk discard is fine)
            excess = len(self._closed) - 5000
            it = iter(self._closed)
            to_remove = [next(it) for _ in range(excess)]
            self._closed -= set(to_remove)
        if q is not None:
            # Wake any blocked get() calls with a proper sentinel
            q.put_nowait(StreamSignal(is_done=True))

        error=msg.error,
    )

async def _receive_stream_signal(
    self,
    request_id: str,
    from_stage: str,
    *,
    is_done: bool = False,
    error: str | None = None,
) -> None:
    if request_id in self._aborted:
        return
    self._active_requests.add(request_id)
    if error:
        await self._queue_stream_error(
            request_id,
            from_stage,
            RuntimeError(error),
        )
        return

    if is_done:
        if not self._open_pre_payload_stream_if_allowed(request_id):
            with suppress(Exception):
                self.scheduler.abort(request_id)
            await self._send_failure(
                request_id,
                (
                    f"Stage {self.name}: stream_done from {from_stage!r} "
                    "arrived before the request payload, but this stage is not "
                    "configured to accept pre-payload stream data"
                ),
            )
            return
        self._stream_queue.put_done(request_id, from_stage=from_stage)
        self.scheduler.inbox.put(
            IncomingMessage(
                request_id=request_id,
                type="stream_done",
            )
        )

def _open_pre_payload_stream_if_allowed(self, request_id: str) -> bool:
    if self._stream_queue is None:
        return False
    if self._stream_queue.has(request_id):
        return True
    if not self._can_accept_stream_before_payload:
        return False
    self._active_requests.add(request_id)
    self._stream_queue.open(request_id)
    return True

def _route_stream_item(self, request_id: str, item: StreamItem) -> None:
    self.scheduler.inbox.put(
        IncomingMessage(request_id=request_id, type="stream_chunk", data=item)
    )

async def _execute(self, payload: Any) -> None:
    request_id = payload.request_id
    _emit_event(
        request_id=request_id,
        stage=self.name,
        event_name="stage_dispatch",
    )
    if (
        self.role == "leader"
        and self._tp_fanout is not None
        and getattr(self.scheduler, "requires_tp_work_fanout", False)
    ):
        self._tp_fanout.fanout_work(payload)
    self.scheduler.inbox.put(
        IncomingMessage(request_id=request_id, type="new_request", data=payload)
    )

async def _on_admin(self, msg: AdminMessage) -> None:
    operation = msg.operation
    if self.role == "leader" and self._tp_fanout is not None:
        local = await self._run_admin_operation(operation)
        try:
            follower_msgs = await self._tp_fanout.collect_admin_results(
                operation.op_id,
                timeout_s=float(
                    60.0 if operation.timeout_s is None else operation.timeout_s
                ),
            )
        except Exception as exc:
            local.success = False
            local.error = str(exc)
